import functions_framework
import hmac
import hashlib
import json
import os
from flask import jsonify

WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', 'your-secret-key-here')

def verify_signature(payload, signature_header):
    """Verify the webhook signature"""
    if not signature_header:
        return False
    
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(expected_signature, signature_header)

@functions_framework.http
def webhook_handler(request):
    """HTTP Cloud Function for processing payment webhooks"""
    
    # Only accept POST requests
    if request.method != 'POST':
        return jsonify({'error': 'Method not allowed'}), 405
    
    # Get the signature from headers
    signature = request.headers.get('X-Webhook-Signature', '')
    
    # Get raw request body for signature verification
    request_body = request.get_data()
    
    # Verify the webhook signature
    if not verify_signature(request_body, signature):
        return jsonify({'error': 'Invalid signature'}), 401
    
    try:
        # Parse the JSON payload
        event_data = request.get_json()
        
        if not event_data:
            return jsonify({'error': 'Invalid JSON payload'}), 400
        
        # Extract event type
        event_type = event_data.get('event_type', '')
        
        # Process different event types
        if event_type == 'payment.success':
            process_payment_success(event_data)
        elif event_type == 'payment.failed':
            process_payment_failed(event_data)
        elif event_type == 'payment.refunded':
            process_payment_refunded(event_data)
        else:
            return jsonify({'error': 'Unknown event type'}), 400
        
        # Return success response
        return jsonify({
            'status': 'success',
            'message': 'Webhook processed successfully',
            'event_id': event_data.get('event_id', '')
        }), 200
        
    except json.JSONDecodeError:
        return jsonify({'error': 'Invalid JSON'}), 400
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

